package com.kalyani.car_rental_backend.coupon.dto;import jakarta.validation.constraints.*;import java.math.BigDecimal;import java.time.LocalDateTime;public class CouponRequest{@NotBlank@Pattern(regexp="^[A-Za-z0-9_-]{3,30}$")public String code;@NotBlank@Pattern(regexp="PERCENT|FLAT")public String discountType;@NotNull@DecimalMin("0.01")public BigDecimal discountValue;public BigDecimal minimumAmount;public BigDecimal maximumDiscount;public LocalDateTime validFrom;public LocalDateTime validUntil;public boolean active=true;public Integer usageLimit;}
